1762782149742.content:
#Requires AutoHotkey v2.0
#UseHook  ; Force hook to override Windows hotkeys

; ============================================
; Ctrl + Alt + 1: Microsoft Teams in Edge
; ============================================
^!1::
{
    teamsURL   := "https://teams.microsoft.com"
    edgeExe    := "msedge.exe"
    teamsTitle := "Milan Pašek"  ; Partial match for your Teams chat window

    SetTitleMatchMode(2)  ; Partial match

    ; Check if any Edge window with Teams is open
    edgeWindows := WinGetList("ahk_exe " . edgeExe)

    foundTeams := false
    for hwnd in edgeWindows
    {
        title := WinGetTitle("ahk_id " . hwnd)
        ; Check if the window title contains Teams indicators
        if (InStr(title, teamsTitle) && InStr(title, "Microsoft Teams"))
        {
            WinActivate("ahk_id " . hwnd)
            foundTeams := true
            break
        }
    }

    if (!foundTeams)
    {
        ; Check if Edge is running at all
        if (edgeWindows.Length > 0)
        {
            ; Edge is open but no Teams tab - open Teams in new tab
            Run("microsoft-edge:" . teamsURL)
        }
        else
        {
            ; Edge is not open - open Edge with Teams
            ; Edge should restore previous tabs automatically
            Run("microsoft-edge:" . teamsURL)

            ; Wait a moment for Edge to open and restore tabs
            Sleep(2000)

            ; Check again if Teams tab was restored
            edgeWindows := WinGetList("ahk_exe " . edgeExe)
            foundTeams := false

            for hwnd in edgeWindows
            {
                title := WinGetTitle("ahk_id " . hwnd)
                if (InStr(title, teamsTitle) && InStr(title, "Microsoft Teams"))
                {
                    WinActivate("ahk_id " . hwnd)
                    foundTeams := true
                    break
                }
            }

            ; If Teams tab still not found after restore, the new tab with Teams should already be open
            ; Just activate Edge
            if (!foundTeams && edgeWindows.Length > 0)
            {
                WinActivate("ahk_id " . edgeWindows[1])
            }
        }
    }
}

