1764842326983.content:
; Microsoft Edge – activate or open and select 7th tab (AutoHotkey v2)
; Hotkey: Ctrl + Alt + 5
#SingleInstance Force

^!5::
{
    edgeExe := "ahk_exe msedge.exe"

    ; 1) Try to find an existing Edge window
    hwnds := WinGetList(edgeExe)
    if hwnds.Length {
        ; Activate first Edge window and jump to 7th tab
        WinActivate "ahk_id " hwnds[1]
        Sleep 80  ; tiny delay to ensure focus
        ; Edge uses Ctrl+1..Ctrl+8 to jump to tab 1..8, Ctrl+9 = last tab
        ; so Ctrl+7 = 7th tab from the left
        Send "^8"
        return
    }

    ; 2) Edge not running → launch it
    edgePath := GetEdgePath()
    if edgePath {
        Run Format('"{1}"', edgePath)
    } else {
        ; Fallback: let Windows try to resolve msedge.exe
        Run "msedge.exe"
    }

    ; 3) Wait for Edge window, then make sure we have a 7th tab and select it
    if WinWait(edgeExe,, 5) {   ; wait up to 5 seconds
        WinActivate edgeExe
        Sleep 200

        ; New Edge window usually starts with 1 tab.
        ; Create 6 more (total 7) using Ctrl+T, then jump to tab 7 with Ctrl+7.
        Loop 6 {
            Send "^t"   ; open new tab
            Sleep 80
        }
        Send "^7"
    } else {
        MsgBox "Could not find or start Microsoft Edge."
    }
}

GetEdgePath() {
    ; Try typical install locations for msedge.exe
    candidates := []

    pf  := EnvGet("ProgramFiles")          ; usually C:\Program Files
    pf86 := EnvGet("ProgramFiles(x86)")    ; usually C:\Program Files (x86)

    if pf
        candidates.Push(pf  . "\Microsoft\Edge\Application\msedge.exe")
    if pf86
        candidates.Push(pf86 . "\Microsoft\Edge\Application\msedge.exe")

    for path in candidates {
        if FileExist(path)
            return path
    }

    ; No known path found
    return ""
}
